### Issue 4 (Medium) -- DRY opportunity with existing mock

The mock body is nearly identical to the `react-native-modalize` mock in `setup.js`. When moved to `setup.js`, extract a shared factory:

```javascript
const createModalizeMock = () => {
  const React = require('react');
  const { View } = require('react-native');
  return React.forwardRef(({ children }, ref) => {
    React.useImperativeHandle(ref, () => ({
      open: jest.fn(),
      close: jest.fn(),
    }));
    return React.createElement(View, { testID: 'modalize' }, children);
  });
};

jest.mock('react-native-modalize', () => {
  return { Modalize: createModalizeMock() };
}, { virtual: true });

jest.mock(
  '@semparar/design-system-app/src/atomic/atoms/Modalize/view',
  () => ({ __esModule: true, default: createModalizeMock() }),
);
```

This keeps the two mocks in sync and makes the intent clear: both mock the same concept (a Modalize component), just exposed differently (named vs default export).

